import React, { useState } from 'react';
import Header from './Header';
import Footer from './Footer';
import MainlLayout from './MainlLayout';
import SideBar from './SideBar';

const DefaultLayout = () => {
    const [sidebarShow, setSidebarShow] = useState(true);

    return (
        <div className="app-container">
          <Header sidebarShow={sidebarShow} setSidebarShow={setSidebarShow} />
          <SideBar sidebarShow={sidebarShow} setSidebarShow={setSidebarShow} />

          {/* Main Content Area with Modern Header */}
          <div className="wrapper d-flex flex-column min-vh-90 wseInfratechBodyBG pt-0">
            {/* Modern Page Header */}
            <div className="page-header">
              <div className="header-content container-fluid">
                <button 
                //   onClick={() => navigate(-1)} 
                  className="header-back-button"
                  aria-label="Go back"
                >
                  <i className="header-back-icon" />
                </button>
                <h1 className="header-title">College Configuration</h1>
              </div>
            </div>

            {/* Main Content */}
            <div className="body flex-grow-1 px-3">
              <MainlLayout />
            </div>

            <Footer />
          </div>
        </div>
      );

};

export default DefaultLayout;
